INSERT INTO users (id, email, password_hash, full_name, role, phone, bio, avatar_url, address_line1, city, state, country, zip_code, is_verified, is_active) VALUES
('a3333333-3333-3333-3333-333333333333', 'aria@artshop.com',    '$2a$12$mmzq1dzNnsR9wA.pQKBUJOUYKaWKY9fQgkE/Sx1tY7PMqISrsKVd2', 'Aria Nakamura',  'seller', '+81-555-0103', 'Ceramicist and sculptor working from my Kyoto studio. I draw inspiration from the quiet symmetry of traditional Japanese gardens.', 'https://picsum.photos/seed/aria-avatar/150/150', '12-3 Higashiyama', 'Kyoto', 'Kyoto', 'Japan', '605-0825', true, true),
('a4444444-4444-4444-4444-444444444444', 'marcus@artshop.com',  '$2a$12$mmzq1dzNnsR9wA.pQKBUJOUYKaWKY9fQgkE/Sx1tY7PMqISrsKVd2', 'Marcus Okonkwo', 'seller', '+234-555-0104', 'Lagos-based photographer documenting light, motion and everyday life across West Africa.', 'https://picsum.photos/seed/marcus-avatar/150/150', '45 Victoria Island', 'Lagos', 'Lagos', 'Nigeria', '101241', true, true),
('a5555555-5555-5555-5555-555555555555', 'yuki@artshop.com',    '$2a$12$mmzq1dzNnsR9wA.pQKBUJOUYKaWKY9fQgkE/Sx1tY7PMqISrsKVd2', 'Yuki Tanaka',    'seller', '+81-555-0105', 'Printmaker and textile artist. Limited-edition linocuts, hand-dyed pieces, and experimental weavings.', 'https://picsum.photos/seed/yuki-avatar/150/150', '8 Shimokitazawa', 'Tokyo',    'Tokyo',    'Japan',   '155-0031', true, true);
