INSERT INTO products (id, seller_id, title, description, price, compare_at_price, category_id, images, thumbnail, stock, sku, tags, medium, dimensions, weight, is_published, is_featured, avg_rating, total_reviews, total_sales, view_count) VALUES
('e3333333-3333-3333-3333-000000000001', 'a3333333-3333-3333-3333-333333333333', 'Tea Bowl — Shino Glaze',           'Wheel-thrown stoneware tea bowl finished with a traditional shino glaze. Warm off-white with soft orange flashes where the flame caught the kiln. Each bowl is signed and stamped.',                               120.00, NULL,   (SELECT id FROM categories WHERE slug = 'handcraft'),  ARRAY['https://picsum.photos/seed/aria-p1a/800/800','https://picsum.photos/seed/aria-p1b/800/800'], 'https://picsum.photos/seed/aria-p1a/500/500',  12, 'AR-CER-001', ARRAY['ceramic','stoneware','tea','japan','wabi-sabi'],       'Stoneware',       '4x4x3 in',    0.4, true,  true,  4.9, 3, 14,  287),
('e3333333-3333-3333-3333-000000000002', 'a3333333-3333-3333-3333-333333333333', 'Moon Jar (Small)',                   'A contemporary take on the classic Korean moon jar. Porcelain, fired once at 1260C, softly pebble-white with subtle surface variation.',                                                                        340.00, 420.00, (SELECT id FROM categories WHERE slug = 'handcraft'),  ARRAY['https://picsum.photos/seed/aria-p2a/800/800'],                                           'https://picsum.photos/seed/aria-p2a/500/500',   4, 'AR-CER-002', ARRAY['porcelain','vessel','minimalist','white'],             'Porcelain',       '8x8x9 in',    1.6, true,  true,  4.8, 2, 6,   168),
('e3333333-3333-3333-3333-000000000003', 'a3333333-3333-3333-3333-333333333333', 'Black Slab Platter',                'Hand-cut slab platter with a matte black oxide finish. Perfect for serving or as a low, sculptural centrepiece.',                                                                                                  185.00, NULL,   (SELECT id FROM categories WHERE slug = 'handcraft'),  ARRAY['https://picsum.photos/seed/aria-p3a/800/800'],                                           'https://picsum.photos/seed/aria-p3a/500/500',   6, 'AR-CER-003', ARRAY['platter','matte','black','functional','serving'],      'Stoneware',       '14x10x1 in',  1.2, true,  false, 4.7, 1, 4,    92),
('e3333333-3333-3333-3333-000000000004', 'a3333333-3333-3333-3333-333333333333', 'Stone Cairn Sculpture',              'A stack of hand-built ceramic forms finished to resemble weathered river stones. A quiet presence for a shelf or side table.',                                                                                   410.00, NULL,   (SELECT id FROM categories WHERE slug = 'sculptures'), ARRAY['https://picsum.photos/seed/aria-p4a/800/800'],                                           'https://picsum.photos/seed/aria-p4a/500/500',   2, 'AR-SCL-001', ARRAY['sculpture','meditative','stone','zen'],                'Ceramic',         '6x6x12 in',   2.1, true,  true,  5.0, 1, 2,    74),
('e3333333-3333-3333-3333-000000000005', 'a3333333-3333-3333-3333-333333333333', 'Vase No. 4 — Deep Indigo',          'Bottle-form vase with a rich deep-indigo tenmoku glaze. Wheel-thrown, a single piece hand-finished and signed underneath.',                                                                                     260.00, NULL,   (SELECT id FROM categories WHERE slug = 'handcraft'),  ARRAY['https://picsum.photos/seed/aria-p5a/800/800','https://picsum.photos/seed/aria-p5b/800/800'], 'https://picsum.photos/seed/aria-p5a/500/500',   5, 'AR-CER-004', ARRAY['vase','indigo','stoneware','contemporary'],            'Stoneware',       '5x5x11 in',   1.3, true,  false, 4.6, 2, 3,   118),
('e3333333-3333-3333-3333-000000000006', 'a3333333-3333-3333-3333-333333333333', 'Ikebana Vessel — Low',              'Low, wide ikebana vessel with a built-in kenzan well. Perfect for minimal single-flower arrangements.',                                                                                                         155.00, NULL,   (SELECT id FROM categories WHERE slug = 'handcraft'),  ARRAY['https://picsum.photos/seed/aria-p6a/800/800'],                                           'https://picsum.photos/seed/aria-p6a/500/500',   8, 'AR-CER-005', ARRAY['ikebana','flower','vessel','japanese'],                 'Stoneware',       '7x7x2 in',    0.9, true,  false, 4.9, 1, 5,    83),
('e3333333-3333-3333-3333-000000000007', 'a3333333-3333-3333-3333-333333333333', 'Raku Incense Holder',               'Traditional raku-fired incense holder with a crackled black-white glaze. Includes a small plate for catching ash.',                                                                                               68.00, NULL,   (SELECT id FROM categories WHERE slug = 'handcraft'),  ARRAY['https://picsum.photos/seed/aria-p7a/800/800'],                                           'https://picsum.photos/seed/aria-p7a/500/500',  15, 'AR-CER-006', ARRAY['raku','incense','small','zen','gift'],                 'Raku ceramic',    '3x3x2 in',    0.2, true,  false, 4.8, 3, 11,  156),
('e3333333-3333-3333-3333-000000000008', 'a3333333-3333-3333-3333-333333333333', 'Form in Three Parts',               'A sculptural study in balance: three interlocking ceramic forms that can be arranged in many configurations. Finished in a cool grey-green ash glaze.',                                                        680.00, NULL,   (SELECT id FROM categories WHERE slug = 'sculptures'), ARRAY['https://picsum.photos/seed/aria-p8a/800/800'],                                           'https://picsum.photos/seed/aria-p8a/500/500',   1, 'AR-SCL-002', ARRAY['sculpture','modular','grey','contemporary'],           'Stoneware',       '18x14x8 in',  4.2, true,  true,  5.0, 1, 1,    52),
('e3333333-3333-3333-3333-000000000009', 'a3333333-3333-3333-3333-333333333333', 'Everyday Mug Set (4)',              'Four mismatched-by-design mugs, each wheel-thrown and glazed in a warm earthen palette. Dishwasher-safe.',                                                                                                      140.00, NULL,   (SELECT id FROM categories WHERE slug = 'handcraft'),  ARRAY['https://picsum.photos/seed/aria-p9a/800/800'],                                           'https://picsum.photos/seed/aria-p9a/500/500',  10, 'AR-CER-007', ARRAY['mug','set','functional','kitchen'],                    'Stoneware',       '4x4x4 in ea', 1.5, true,  false, 4.7, 2, 7,   141),
('e3333333-3333-3333-3333-00000000000a', 'a3333333-3333-3333-3333-333333333333', 'Shelf Figure — Crane',              'Small abstracted crane figure in unglazed porcelain. A quiet detail for a bookshelf or mantelpiece.',                                                                                                            95.00, NULL,   (SELECT id FROM categories WHERE slug = 'sculptures'), ARRAY['https://picsum.photos/seed/aria-p10a/800/800'],                                          'https://picsum.photos/seed/aria-p10a/500/500',  7, 'AR-SCL-003', ARRAY['figure','porcelain','bird','minimalist'],              'Porcelain',       '3x3x7 in',    0.3, true,  false, 4.5, 0, 0,    38);
INSERT INTO products (id, seller_id, title, description, price, compare_at_price, category_id, images, thumbnail, stock, sku, tags, medium, dimensions, weight, is_published, is_featured, avg_rating, total_reviews, total_sales, view_count) VALUES
('f4444444-4444-4444-4444-000000000001', 'a4444444-4444-4444-4444-444444444444', 'Lagos Morning — No. 3',              'Lagos waking up under a soft haze. Shot on medium format film at dawn in January. Edition of 15.',                                                                                                             220.00, NULL,   (SELECT id FROM categories WHERE slug = 'photography'), ARRAY['https://picsum.photos/seed/marcus-p1a/800/1000'],                                        'https://picsum.photos/seed/marcus-p1a/500/625',  15, 'MO-PH-001', ARRAY['lagos','morning','film','africa','street'],            'Archival pigment print',    '12x16 in', 0.5, true, true,  4.8, 4, 9,  294),
('f4444444-4444-4444-4444-000000000002', 'a4444444-4444-4444-4444-444444444444', 'Okavango Reflections',              'A long-exposure study of still water in the Okavango delta. Cool blues and a single silhouette. Edition of 10.',                                                                                                380.00, NULL,   (SELECT id FROM categories WHERE slug = 'photography'), ARRAY['https://picsum.photos/seed/marcus-p2a/800/1200'],                                        'https://picsum.photos/seed/marcus-p2a/500/750',  10, 'MO-PH-002', ARRAY['landscape','water','africa','minimal','blue'],          'Archival pigment print',    '16x24 in', 0.9, true, true,  5.0, 2, 3,  162),
('f4444444-4444-4444-4444-000000000003', 'a4444444-4444-4444-4444-444444444444', 'Market Study No. 7',                'Detail from Balogun market. Strong mid-day light, blue fabrics against an ochre wall. Edition of 20.',                                                                                                          165.00, NULL,   (SELECT id FROM categories WHERE slug = 'photography'), ARRAY['https://picsum.photos/seed/marcus-p3a/800/1000'],                                        'https://picsum.photos/seed/marcus-p3a/500/625',  20, 'MO-PH-003', ARRAY['market','street','colour','africa','documentary'],     'Archival pigment print',    '12x16 in', 0.5, true, false, 4.7, 3, 11, 201),
('f4444444-4444-4444-4444-000000000004', 'a4444444-4444-4444-4444-444444444444', 'Boy With Kite',                     'A single frame from a Saturday afternoon on Tarkwa Bay. Captured with a Leica M6 on Tri-X. Edition of 15.',                                                                                                    195.00, NULL,   (SELECT id FROM categories WHERE slug = 'photography'), ARRAY['https://picsum.photos/seed/marcus-p4a/800/1000'],                                        'https://picsum.photos/seed/marcus-p4a/500/625',  15, 'MO-PH-004', ARRAY['portrait','film','bw','documentary'],                  'Silver gelatin print',      '12x16 in', 0.5, true, false, 4.9, 1, 2,   94),
('f4444444-4444-4444-4444-000000000005', 'a4444444-4444-4444-4444-444444444444', 'Crossing the Bridge',               'Evening commuters on Third Mainland Bridge. Shot through a long lens, soft gradients, a sense of quiet in motion.',                                                                                             240.00, 290.00, (SELECT id FROM categories WHERE slug = 'photography'), ARRAY['https://picsum.photos/seed/marcus-p5a/800/1000'],                                        'https://picsum.photos/seed/marcus-p5a/500/625',   8, 'MO-PH-005', ARRAY['city','evening','motion','blur'],                       'Archival pigment print',    '16x20 in', 0.7, true, true,  4.6, 2, 4,  138),
('f4444444-4444-4444-4444-000000000006', 'a4444444-4444-4444-4444-444444444444', 'Desert Palette',                    'Triptych of sand and sky textures from northern Senegal. Warm earth tones. Sold as a set of three 10x12 prints.',                                                                                                420.00, NULL,   (SELECT id FROM categories WHERE slug = 'photography'), ARRAY['https://picsum.photos/seed/marcus-p6a/800/600'],                                         'https://picsum.photos/seed/marcus-p6a/500/375',   6, 'MO-PH-006', ARRAY['desert','triptych','warm','abstract','landscape'],     'Archival pigment print',    '30x12 in', 1.0, true, true,  4.8, 1, 2,   88),
('f4444444-4444-4444-4444-000000000007', 'a4444444-4444-4444-4444-444444444444', 'Grandmother''s Courtyard',         'Portrait of light moving across an empty courtyard at golden hour. Warm, quiet, still.',                                                                                                                        210.00, NULL,   (SELECT id FROM categories WHERE slug = 'photography'), ARRAY['https://picsum.photos/seed/marcus-p7a/800/1000'],                                        'https://picsum.photos/seed/marcus-p7a/500/625',  12, 'MO-PH-007', ARRAY['light','architecture','warm','home'],                  'Archival pigment print',    '12x16 in', 0.5, true, false, 4.9, 2, 4,  107),
('f4444444-4444-4444-4444-000000000008', 'a4444444-4444-4444-4444-444444444444', 'Rain on Campus',                    'Moody black-and-white of students sheltering from a sudden downpour at the University of Lagos.',                                                                                                               170.00, NULL,   (SELECT id FROM categories WHERE slug = 'photography'), ARRAY['https://picsum.photos/seed/marcus-p8a/800/1000'],                                        'https://picsum.photos/seed/marcus-p8a/500/625',  14, 'MO-PH-008', ARRAY['bw','rain','campus','documentary'],                   'Silver gelatin print',      '12x16 in', 0.5, true, false, 4.5, 0, 1,   69),
('f4444444-4444-4444-4444-000000000009', 'a4444444-4444-4444-4444-444444444444', 'Low Tide, Elegushi',                'Long exposure at Elegushi beach near sunset. Smooth water, grain, and a single silhouette. Edition of 12.',                                                                                                     260.00, NULL,   (SELECT id FROM categories WHERE slug = 'photography'), ARRAY['https://picsum.photos/seed/marcus-p9a/800/1000'],                                        'https://picsum.photos/seed/marcus-p9a/500/625',  12, 'MO-PH-009', ARRAY['beach','long-exposure','water','sunset'],              'Archival pigment print',    '16x20 in', 0.7, true, true,  4.7, 1, 2,  114),
('f4444444-4444-4444-4444-00000000000a', 'a4444444-4444-4444-4444-444444444444', 'Four Doors',                        'A typology study — four weathered doors from Old Lagos, shot the same time of day to match the light. Sold as a set of four 8x10 prints.',                                                                     310.00, NULL,   (SELECT id FROM categories WHERE slug = 'photography'), ARRAY['https://picsum.photos/seed/marcus-p10a/800/800'],                                        'https://picsum.photos/seed/marcus-p10a/500/500',  9, 'MO-PH-010', ARRAY['typology','architecture','set','warm'],                'Archival pigment print',    '16x20 in', 0.8, true, false, 4.8, 1, 1,   61);
