('c5555555-5555-5555-5555-000000000001', 'a5555555-5555-5555-5555-555555555555', 'Linocut — Garden After Rain',        'Hand-pulled linocut print in four colours. Made with oil-based ink on heavy cotton paper. Edition of 30.',                                                                                                      95.00,  NULL,   (SELECT id FROM categories WHERE slug = 'prints'),       ARRAY['https://picsum.photos/seed/yuki-p1a/800/1000'],                                          'https://picsum.photos/seed/yuki-p1a/500/625',  28, 'YT-PR-001', ARRAY['linocut','print','garden','green','handmade'],         'Linocut on cotton paper',   '11x14 in', 0.2, true, true,  4.9, 5, 12, 212),
('c5555555-5555-5555-5555-000000000002', 'a5555555-5555-5555-5555-555555555555', 'Indigo Wave — Shibori Wall Hanging','Hand-dyed cotton fabric using traditional Japanese shibori resist technique. Ready to hang with a pale oak rod included.',                                                                                       280.00, NULL,   (SELECT id FROM categories WHERE slug = 'textile-art'),  ARRAY['https://picsum.photos/seed/yuki-p2a/800/1000'],                                          'https://picsum.photos/seed/yuki-p2a/500/625',   6, 'YT-TX-001', ARRAY['shibori','indigo','textile','wall-hanging'],           'Hand-dyed cotton',          '20x30 in', 0.6, true, true,  4.8, 3, 5,  154),
('c5555555-5555-5555-5555-000000000003', 'a5555555-5555-5555-5555-555555555555', 'Moth Study — Silkscreen',            'Two-colour silkscreen print of a hawk moth on cream paper. Edition of 40.',                                                                                                                                       60.00,  NULL,   (SELECT id FROM categories WHERE slug = 'prints'),       ARRAY['https://picsum.photos/seed/yuki-p3a/800/1000'],                                          'https://picsum.photos/seed/yuki-p3a/500/625',  40, 'YT-PR-002', ARRAY['silkscreen','moth','natural','small'],                 'Silkscreen',                '8x10 in',  0.1, true, false, 4.7, 2, 8,  178),
('c5555555-5555-5555-5555-000000000004', 'a5555555-5555-5555-5555-555555555555', 'Kintsugi Collage No. 1',            'A collage of torn handmade papers joined with gold paint, echoing the Japanese kintsugi tradition of repair.',                                                                                                   340.00, NULL,   (SELECT id FROM categories WHERE slug = 'mixed-media'),  ARRAY['https://picsum.photos/seed/yuki-p4a/800/1000'],                                          'https://picsum.photos/seed/yuki-p4a/500/625',   3, 'YT-MM-001', ARRAY['kintsugi','collage','gold','handmade','contemporary'], 'Paper, gold leaf',          '16x20 in', 0.3, true, true,  4.9, 1, 2,   84),
('c5555555-5555-5555-5555-000000000005', 'a5555555-5555-5555-5555-555555555555', 'Forest Series — Riso Print',         'Two-colour risograph print in green and navy. Slightly grainy, warm to the touch. Edition of 50.',                                                                                                                45.00,  60.00,  (SELECT id FROM categories WHERE slug = 'prints'),       ARRAY['https://picsum.photos/seed/yuki-p5a/800/1000'],                                          'https://picsum.photos/seed/yuki-p5a/500/625',  44, 'YT-PR-003', ARRAY['risograph','forest','affordable','print'],             'Risograph',                 '8x10 in',  0.1, true, false, 4.6, 3, 15, 221),
('c5555555-5555-5555-5555-000000000006', 'a5555555-5555-5555-5555-555555555555', 'Woven Wall Piece — Snow',            'Small woven wall piece in natural wool and linen, warm whites with a single black thread running through.',                                                                                                      225.00, NULL,   (SELECT id FROM categories WHERE slug = 'textile-art'),  ARRAY['https://picsum.photos/seed/yuki-p6a/800/1000'],                                          'https://picsum.photos/seed/yuki-p6a/500/625',   5, 'YT-TX-002', ARRAY['weaving','wool','white','textile','minimalist'],       'Wool, linen',               '14x22 in', 0.4, true, false, 4.8, 1, 3,   96),
('c5555555-5555-5555-5555-000000000007', 'a5555555-5555-5555-5555-555555555555', 'Paper Map — Tokyo Streets',         'Hand-drawn, hand-printed map of my Shimokitazawa neighbourhood. Single-colour letterpress on natural paper.',                                                                                                     75.00,  NULL,   (SELECT id FROM categories WHERE slug = 'prints'),       ARRAY['https://picsum.photos/seed/yuki-p7a/800/1000'],                                          'https://picsum.photos/seed/yuki-p7a/500/625',  18, 'YT-PR-004', ARRAY['map','tokyo','letterpress','handmade'],                'Letterpress',               '11x17 in', 0.2, true, false, 4.9, 1, 5,  132),
('c5555555-5555-5555-5555-000000000008', 'a5555555-5555-5555-5555-555555555555', 'Embroidered Panel — Moss',          'Small embroidered panel on natural linen in mossy greens. Mounted on a hidden wooden stretcher.',                                                                                                                195.00, NULL,   (SELECT id FROM categories WHERE slug = 'textile-art'),  ARRAY['https://picsum.photos/seed/yuki-p8a/800/800'],                                           'https://picsum.photos/seed/yuki-p8a/500/500',   4, 'YT-TX-003', ARRAY['embroidery','green','textile','small'],                'Embroidery on linen',       '10x10 in', 0.2, true, false, 4.7, 0, 0,    47),
('c5555555-5555-5555-5555-000000000009', 'a5555555-5555-5555-5555-555555555555', 'Three Moons — Etching Set',         'A set of three small etchings — waxing, full, and waning moons. Each signed and numbered. Edition of 25 sets.',                                                                                                 140.00, NULL,   (SELECT id FROM categories WHERE slug = 'prints'),       ARRAY['https://picsum.photos/seed/yuki-p9a/800/600'],                                           'https://picsum.photos/seed/yuki-p9a/500/375',  22, 'YT-PR-005', ARRAY['etching','moon','set','intimate'],                     'Etching',                   '18x6 in',  0.2, true, true,  5.0, 2, 7,  169),
('c5555555-5555-5555-5555-00000000000a', 'a5555555-5555-5555-5555-555555555555', 'Found-Paper Collage — Sora',        'Large collage built from decades-old book pages and hand-painted paper scraps. Titled ''Sora'' (sky).',                                                                                                           520.00, 640.00, (SELECT id FROM categories WHERE slug = 'mixed-media'),  ARRAY['https://picsum.photos/seed/yuki-p10a/800/1000'],                                         'https://picsum.photos/seed/yuki-p10a/500/625',  1, 'YT-MM-002', ARRAY['collage','paper','vintage','mixed-media','large'],     'Mixed media on panel',      '24x30 in', 1.1, true, true,  4.8, 1, 1,    58);
