INSERT INTO reviews (product_id, user_id, rating, title, comment, is_verified_purchase, helpful_count, created_at) VALUES
('e3333333-3333-3333-3333-000000000002', 'b6666666-6666-6666-6666-666666666666', 5, 'A centrepiece in every room',       'Every visitor picks it up. The glaze has real depth in person — photos don''t do it justice. Packaging was flawless.', true, 9, NOW() - INTERVAL '22 days'),
('e3333333-3333-3333-3333-000000000002', 'b1111111-1111-1111-1111-111111111111', 5, 'Exactly what I wanted',             'Exactly the kind of quiet presence I was looking for. Pairs perfectly with minimal interiors.',                       false, 3, NOW() - INTERVAL '12 days'),
('e3333333-3333-3333-3333-000000000001', 'b8888888-8888-8888-8888-888888888888', 5, 'Daily ritual',                      'I use it every morning. The shino flashes make each bowl feel one-of-a-kind.',                                         false, 4, NOW() - INTERVAL '8 days'),
('e3333333-3333-3333-3333-000000000001', 'b1111111-1111-1111-1111-111111111111', 5, 'Small but soulful',                 'Smaller than I expected but honestly the proportions are just right. Delivery was quick.',                             false, 2, NOW() - INTERVAL '3 days'),
('e3333333-3333-3333-3333-000000000001', 'b2222222-2222-2222-2222-222222222222', 4, 'Lovely — a touch smaller',          'Lovely finish, warm and tactile. Photos made it look a bit bigger than it is — worth zooming in on the dimensions.',   false, 1, NOW() - INTERVAL '2 days'),
('f4444444-4444-4444-4444-000000000001', 'b7777777-7777-7777-7777-777777777777', 5, 'Print quality is excellent',        'Framed it behind museum glass. The tonal range is beautifully preserved. Signed and numbered as promised.',            true,  6, NOW() - INTERVAL '30 days'),
('f4444444-4444-4444-4444-000000000001', 'b1111111-1111-1111-1111-111111111111', 5, 'A keeper',                          'Arrived flat, well-wrapped, in under a week. Paper quality is gorgeous.',                                              false, 2, NOW() - INTERVAL '10 days'),
('f4444444-4444-4444-4444-000000000003', 'b2222222-2222-2222-2222-222222222222', 5, 'Colours pop',                       'The blues against the ochre wall are incredible. One of the best prints I''ve bought online.',                         false, 3, NOW() - INTERVAL '20 days'),
('f4444444-4444-4444-4444-000000000003', 'b3333333-3333-3333-3333-333333333333', 4, 'Slightly cropped',                  'Beautiful image. My only note is the white border is narrower than I''d like for my frame — easy enough to mount.',    false, 0, NOW() - INTERVAL '14 days'),
('c5555555-5555-5555-5555-000000000001', 'b8888888-8888-8888-8888-888888888888', 5, 'Beautiful handmade feel',           'You can feel the paper. Signed, numbered, and carefully packed. Would buy again.',                                     false, 5, NOW() - INTERVAL '18 days'),
('c5555555-5555-5555-5555-000000000005', 'b6666666-6666-6666-6666-666666666666', 4, 'Great at this price',               'Risograph grain is lovely. For under 50 USD it''s a very honest object.',                                              false, 2, NOW() - INTERVAL '16 days'),
('c5555555-5555-5555-5555-000000000009', 'b7777777-7777-7777-7777-777777777777', 5, 'Tiny and perfect',                  'Hung together as a row above my desk. The etching lines are delicate and rich.',                                       true,  1, NOW() - INTERVAL '7 days');
